mapper.select:
select ri.id, ri.room_number, ri.rent, ri.apartment_id, ri.is_release, ri.publisher_type, ri.publisher_id, ri.review_status, ri.compliance_score, ri.last_reviewed_at, la.room_id is not null is_check_in, la.lease_end_date, ai.id apart_id, ai.name, ai.introduction, ai.district_id, ai.district_name, ai.city_id, ai.city_name, ai.province_id, ai.province_name, ai.address_detail, ai.latitude, ai.longitude, ai.phone, ai.is_release apart_is_release, rr.id review_id, rr.reviewer_id, su.name reviewer_name, rr.status review_review_status, rr.compliance_score review_compliance_score, rr.photo_quality_score, rr.description_accuracy_score, rr.facility_completeness_score, rr.location_accuracy_score, rr.overall_rating, rr.review_comments, rr.rejection_reasons, rr.reviewed_at from room_info ri left join lease_agreement la on ri.id = la.room_id and la.is_deleted = 0 and la.status in (2,5) left join apartment_info ai on ri.apartment_id = ai.id and ai.is_deleted = 0 left join ( select rr1.* from room_review rr1 inner join ( select room_id, max(create_time) as max_time from room_review where is_deleted = 0 group by room_id ) rr2 on rr1.room_id = rr2.room_id and rr1.create_time = rr2.max_time where rr1.is_deleted = 0 ) rr on ri.id = rr.room_id and ri.publisher_type = 2 left join system_user su on rr.reviewer_id = su.id and su.is_deleted = 0
ri.is_deleted = 0
and ai.province_id = #{queryVo.provinceId}
and ai.city_id = #{queryVo.cityId}
and ai.district_id = #{queryVo.districtId}
and ri.apartment_id = #{queryVo.apartmentId}
and ri.publisher_type = #{queryVo.publisherType}
